import React, { HTMLAttributes } from "react";
import MessageBlock from "../common/MessageBlock";

import react_native_01 from "../../assets/images/react_native_01.jpg";
import react_native_02 from "../../assets/images/react_native_02.jpg";
import react_native_03 from "../../assets/images/react_native_03.jpg";
import react_native_04 from "../../assets/images/react_native_04.jpg";
import wpf_01 from "../../assets/images/wpf_01.jpg";

import wpf_v1_01 from "../../assets/images/wpf_v1_01.jpg";
import wpf_v1_02 from "../../assets/images/wpf_v1_02.jpg";

import "./Portfolio.scss";
import { Grid } from "@material-ui/core";
import Spacer from "../Spacer";

const ClickableImage = ({ src, ...props }:
  { src: string } & HTMLAttributes<HTMLImageElement>
) => {
  return <img onClick={() => {
    window.open(src, '_blank')
  }} src={src} {...props} />
}


export default () => {
  return (
    <div className="portfolio">
      <MessageBlock title={"Personal Project IV (By Tensorflow and OpenImage Dataset)"} >


      </MessageBlock>

      <Spacer />
      <Spacer />

      <MessageBlock title={"Personal Project III (By React-Native and Docker)"} >
        <p>
          Having created my project II below on windows presentation form, I have decided to learn how to build mobile application in order to view my
          screenshots and vocabularies, etc, on mobile so that I can ready them everywhere. I have deployed
          two ec2 instances, with one running a docker container of a mySQL server and one running a docker
          container of my Spring-Hibernate application
        </p>

        <div className="video-row">
          <iframe width="560" height="315" src="https://www.youtube.com/embed/iJL0PS9wojc" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"></iframe>
        </div>




        <div className="image-row project-03">
          <Grid container>
            <Grid item md={12} className="item">
              <ClickableImage src={react_native_04} />
            </Grid>
          </Grid>
        </div>
      </MessageBlock>
      <Spacer />
      <Spacer />
      <MessageBlock title={"Personal Project II (By Window Presentation Form, namely, C# and .net)"} >
        <p>I have been a hard-core player in two games: the granblue fantasy and the
        final fantasy 14 (currently still an active player). Both have a very rich story with their own gigantic
        world, but unfortunately both of them have no content availalable in Chinese.
        </p>

        <p>
          This serves as a motivation for me to create an application that: Without interrupting the gameflow,
          users can save each screenshot, can go back and review the content of each page, jot down their dictionary, and categorize their screenshots by "note":
        </p>

        <div className="video-row">
          <iframe width="560" height="315" src="https://www.youtube.com/embed/GM1Ec79vlG8" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" ></iframe>
          <Spacer />
        </div>

        <Spacer />
        <Spacer />
        <p>
          Users can save their dictionaries for review. And they can capture the text from screenshot by the
          tool I developed in the previous project, which is already integrated into this application.
          The whole application is created by WPF in .net framework and recently has been transited into
          .net-core 3.

        </p>
      </MessageBlock>

      <Spacer />
      <Spacer />
      <MessageBlock title={"Personal Project I (By Window Presentation Form, namely, C# and .net)"} >
        <p>
          This is my first windows application in an attempt to assist my work in eLearningPro.
        </p>


        <p>
          I had been working on transforming old flash games into HTML5 games. Occasionally it is impossible
          to copy the texts of the animated texts from the original .fla file, to extract the texts I make the
          following application.
        </p>

        <div className="image-row project-01">
          <Grid container>
            <Grid item md={6} className="item">
              <ClickableImage src={wpf_v1_01} />
            </Grid>
            <Grid item md={6} className="item">
              <ClickableImage src={wpf_v1_02} />
            </Grid>
          </Grid>
        </div>

        <p>
          This application was first developed in Python with a library called tkinter, and turned into a standalone .exe file by using pyinstaller (detail is also listed in my github). The journey of bug fixing prompt me to develop this application directly in C#.

        </p>
      </MessageBlock>
    </div >
  )
}