import React, { ReactNode } from "react";

import { makeStyles } from '@material-ui/core/styles';
import Timeline from '@material-ui/lab/Timeline';
import TimelineItem from '@material-ui/lab/TimelineItem';
import TimelineSeparator from '@material-ui/lab/TimelineSeparator';
import TimelineConnector from '@material-ui/lab/TimelineConnector';
import TimelineContent from '@material-ui/lab/TimelineContent';
import TimelineOppositeContent from '@material-ui/lab/TimelineOppositeContent';
import TimelineDot from '@material-ui/lab/TimelineDot';
import Paper from '@material-ui/core/Paper';
import Typography from '@material-ui/core/Typography';
import "./CustomTimeline.scss";
import Spacer from "../Spacer";

const useStyles = makeStyles((theme) => ({
  paper: {
    padding: '6px 16px',
  },
  secondaryTail: {
    backgroundColor: theme.palette.secondary.main,
  },
}));


export default ({ items, alignment = "left", dotVarient }: {
  items?: {
    date: string,
    title: string,
    description: string,
    icon?: ReactNode,
    link?: string
  }[],
  alignment?: "left" | "right" | "alternate",
  dotVarient?: "outlined"
}) => {
  const classes = useStyles();

  if (!items) return <></>

  return (
    items && <Timeline align={alignment} className="custom-timeline">
      {items.map((item, index) => {
        const { date, title, description, icon, link } = item;
        return (
          <TimelineItem key={`${title}_${index}`}>
            <TimelineOppositeContent>
              <div className="date">
                <Typography variant="body2" color="textSecondary">
                  {date}
                </Typography>
              </div>
            </TimelineOppositeContent>
            <TimelineSeparator>
              <TimelineDot variant={dotVarient}>
                {icon}
              </TimelineDot>
              <TimelineConnector />
            </TimelineSeparator>
            <TimelineContent>
              <div className="timeline-card">
                <div className="title">{title}</div>
                <Spacer height={5} />
                <div className="description">{description} </div>
                {link && <div className="url-link">
                  link: <a href={link} target="_blank">{link}</a>
                </div>}
              </div>
            </TimelineContent>
          </TimelineItem>
        )
      })}
    </Timeline>)
}