import { AnyAction } from "redux";
import { ChangeActiveTag, CHANGE_ACTIVE_TAG, CLOSE_LEFT_MENU, OPEN_LEFT_MENU } from "../actions/app.actions";
import { TAppState } from "../models/app.state";

const initialState: TAppState = {
  activeTag: "about",
  leftMenuIsOpen: false
}

export default (state: TAppState = initialState, action: AnyAction): TAppState => {
  switch (action.type) {
    case CHANGE_ACTIVE_TAG:
      const { activeTag } = (action as ChangeActiveTag).payload;
      return { ...state, activeTag };

    case CLOSE_LEFT_MENU:
      return { ...state, leftMenuIsOpen: false };

    case OPEN_LEFT_MENU:
      return { ...state, leftMenuIsOpen: true };

    default:
      return state;
  }
}