import React, { useEffect } from 'react';
import logo from './logo.svg';
import './App.scss';
import { Col, Container, Row } from 'react-bootstrap';
import my_picture from "./assets/images/my_picture.jpg";
import LeftMenu from "./components/common/LeftMenu";
import MainContent from "./components/common/MainContent";
import Spacer from "./components/Spacer";
import { Switch, Route, useLocation } from "react-router-dom";
import routes from "./routers/routers";
import { changeActiveTag, closeLeftMenu, openLeftMenu } from './redux/actions/app.actions';
import routeKeys from './constants/routeKeys';
import { useDispatch } from 'react-redux';
import useIsMobile from './hooks/useIsMobile';

export default () => {
  const dispatch = useDispatch();
  const { pathname } = useLocation();
  const { isMobile } = useIsMobile();

  useEffect(() => {
    if (isMobile) {
      dispatch(closeLeftMenu());
    } else {
      dispatch(openLeftMenu());
    }
  }, [isMobile])

  useEffect(() => {
    if (pathname.startsWith(`/${routeKeys.about}`)) dispatch(changeActiveTag(routeKeys.about));
    if (pathname.startsWith(`/${routeKeys.skills}`)) dispatch(changeActiveTag(routeKeys.skills));
    if (pathname.startsWith(`/${routeKeys.portfolio}`)) dispatch(changeActiveTag(routeKeys.portfolio));
    if (pathname.startsWith(`/${routeKeys.experience}`)) dispatch(changeActiveTag(routeKeys.experience));
    if (pathname.startsWith(`/${routeKeys.blog}`)) dispatch(changeActiveTag(routeKeys.blog));
    if (pathname.startsWith(`/${routeKeys.contact}`)) dispatch(changeActiveTag(routeKeys.contact));
  }, [pathname])

  return (
    <div className="App">
      <div className="main">
        <LeftMenu />
        <Switch>
          {routes.map(r => (
            <Route
              key={r.routeKey}
              path={r.path}
              component={r.component}
              exact={r.exact}
            />)
          )}
        </Switch>
      </div>
    </div>
  );
}

